function logTime(req, res, next) {
  console.log(req.method + " " + req.url);
  next();
}

app.use(logTime);  // registered before the routes it should cover

If you forget next(), the request enters logTime and never leaves: no route runs, no response is sent, and the browser hangs until it times out. A middleware must either call next() or send a response.

